<?php
declare(strict_types=1);
require_once __DIR__ . '/includes/auth.php'; requireAdmin();
require_once dirname(__DIR__) . '/includes/consultation.php';
$pdo=db();$settings=consultationSettings($pdo);$errors=[];
if($_SERVER['REQUEST_METHOD']==='POST'){
 if(!csrfIsValid($_POST['csrf_token']??null))$errors[]='Security check failed.';else try{$action=$_POST['action']??'';$id=(int)($_POST['id']??0);
  if($action==='update'&&$id){$status=$_POST['status']??'';if(!in_array($status,CONSULTATION_STATUSES,true))throw new RuntimeException('Invalid status.');$old=$pdo->prepare('SELECT * FROM consultation_bookings WHERE id=?');$old->execute([$id]);$booking=$old->fetch();if(!$booking)throw new RuntimeException('Booking not found.');$pdo->prepare('UPDATE consultation_bookings SET status=?,admin_notes=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute([$status,mb_substr(trim((string)($_POST['admin_notes']??'')),0,5000),$id]);if($booking['status']!==$status){$booking['status']=$status;consultationNotify($booking,$settings,$status);}}
  elseif($action==='delete'&&$id){$q=$pdo->prepare('SELECT stored_name FROM consultation_attachments WHERE booking_id=?');$q->execute([$id]);foreach($q->fetchAll(PDO::FETCH_COLUMN)as$f){$path=dirname(__DIR__).'/uploads/consultations/'.basename($f);if(is_file($path))unlink($path);}$pdo->prepare('DELETE FROM consultation_bookings WHERE id=?')->execute([$id]);}
  elseif($action==='settings'){$days=array_values(array_intersect(array_map('intval',(array)($_POST['business_days']??[])),[1,2,3,4,5,6,7]));$email=trim((string)($_POST['admin_email']??''));if(!$days)throw new RuntimeException('Select at least one business day.');if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL))throw new RuntimeException('Enter a valid notification email.');$pdo->prepare('UPDATE consultation_settings SET business_days=?,admin_email=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute([implode(',',$days),$email,$settings['id']]);}
  else throw new RuntimeException('Invalid request.');$_SESSION['consultation_flash']='Changes saved.';header('Location: consultations.php');exit;
 }catch(Throwable$e){$errors[]=$e->getMessage();}}
$where=[];$params=[];$search=trim((string)($_GET['search']??''));$status=(string)($_GET['status']??'');if($search!==''){$where[]='(reference_number LIKE :q OR full_name LIKE :q OR mobile_number LIKE :q OR email LIKE :q)';$params[':q']='%'.$search.'%';}if(in_array($status,CONSULTATION_STATUSES,true)){$where[]='status=:status';$params[':status']=$status;}$q=$pdo->prepare('SELECT * FROM consultation_bookings'.($where?' WHERE '.implode(' AND ',$where):'').' ORDER BY consultation_date DESC,time_slot DESC');$q->execute($params);$bookings=$q->fetchAll();$today=date('Y-m-d');$todayQ=$pdo->prepare('SELECT COUNT(*) FROM consultation_bookings WHERE consultation_date=?');$todayQ->execute([$today]);$stats=['Total Bookings'=>(int)$pdo->query('SELECT COUNT(*) FROM consultation_bookings')->fetchColumn(),"Today's Bookings"=>(int)$todayQ->fetchColumn(),'Upcoming Consultations'=>(int)$pdo->query("SELECT COUNT(*) FROM consultation_bookings WHERE consultation_date>=date('now') AND status NOT IN ('Cancelled','Completed')")->fetchColumn(),'Completed Consultations'=>(int)$pdo->query("SELECT COUNT(*) FROM consultation_bookings WHERE status='Completed'")->fetchColumn(),'Cancelled Consultations'=>(int)$pdo->query("SELECT COUNT(*) FROM consultation_bookings WHERE status='Cancelled'")->fetchColumn()];$edit=null;if(isset($_GET['edit'])){$q=$pdo->prepare('SELECT * FROM consultation_bookings WHERE id=?');$q->execute([(int)$_GET['edit']]);$edit=$q->fetch();}$flash=$_SESSION['consultation_flash']??'';unset($_SESSION['consultation_flash']);$pageTitle='Consultation Management';require __DIR__.'/includes/header.php';
?>
<header class="admin-header"><a class="admin-brand" href="dashboard.php">Design24 Studio Admin</a><div class="admin-user"><span>Signed in as <?=e(currentAdminName())?></span><form method="post" action="logout.php"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><button class="logout-button">Logout</button></form></div></header><main class="admin-main"><section class="panel"><div class="settings-toolbar"><div><h1>Consultation Management</h1><p>Requests, availability, confirmation and follow-up notes.</p></div><a href="dashboard.php">← Dashboard</a></div><?php if($flash):?><p class="success"><?=e($flash)?></p><?php endif?><?php if($errors):?><div class="error"><?=e(implode(' ',$errors))?></div><?php endif?><div class="placeholder-grid"><?php foreach($stats as$n=>$v):?><div class="placeholder"><strong><?=e($n)?></strong><p style="font-size:2rem;margin:5px 0 0"><?=number_format($v)?></p></div><?php endforeach?></div><form class="settings-section" method="get"><div class="settings-grid"><div class="field"><label>Search</label><input name="search" value="<?=e($search)?>" placeholder="Reference, name, phone, email"></div><div class="field"><label>Status</label><select name="status"><option value="">All statuses</option><?php foreach(CONSULTATION_STATUSES as$v):?><option <?=$status===$v?'selected':''?>><?=$v?></option><?php endforeach?></select></div></div><button class="primary-button" style="width:auto;padding:0 22px">Filter</button></form><section class="settings-section" style="overflow:auto"><h2>Bookings</h2><table style="width:100%;border-collapse:collapse;min-width:700px"><thead><tr style="text-align:left"><th>Reference / Client</th><th>Appointment</th><th>Project</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($bookings as$b):?><tr style="border-top:1px solid #d9e2de"><td style="padding:12px 4px"><strong><?=e($b['reference_number'])?></strong><br><?=e($b['full_name'])?><br><small><?=e($b['mobile_number'])?></small></td><td><?=e($b['consultation_date'])?><br><?=e($b['time_slot'])?><br><small><?=e($b['consultation_type'])?></small></td><td><?=e($b['project_type'])?></td><td><?=e($b['status'])?></td><td><a href="?edit=<?=$b['id']?>">Manage</a></td></tr><?php endforeach?><?php if(!$bookings):?><tr><td colspan="5" style="padding:14px">No bookings found.</td></tr><?php endif?></tbody></table></section><?php if($edit):?><form class="settings-section" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="action" value="update"><input type="hidden" name="id" value="<?=$edit['id']?>"><h2><?=e($edit['reference_number'])?> — <?=e($edit['full_name'])?></h2><p><?=e($edit['email'])?> · <?=e($edit['mobile_number'])?><br><?=e($edit['consultation_date'])?> at <?=e($edit['time_slot'])?> · <?=e($edit['project_type'])?></p><p><?=nl2br(e($edit['project_details']))?></p><div class="settings-grid"><div class="field"><label>Status</label><select name="status"><?php foreach(CONSULTATION_STATUSES as$v):?><option <?=$edit['status']===$v?'selected':''?>><?=$v?></option><?php endforeach?></select></div><div class="field"><label>Admin notes</label><textarea name="admin_notes"><?=e($edit['admin_notes'])?></textarea></div></div><button class="primary-button" style="width:auto;padding:0 22px">Save booking</button></form><form method="post" onsubmit="return confirm('Delete this booking permanently?')"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=$edit['id']?>"><button class="secondary-admin-button" type="submit">Delete booking</button></form><?php endif?><form class="settings-section" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="action" value="settings"><h2>Availability &amp; notifications</h2><div class="checkbox-field"><?php $days=consultationBusinessDays($settings);foreach(['Mon','Tue','Wed','Thu','Fri','Sat','Sun']as$i=>$d):?><label style="margin-right:14px"><input type="checkbox" name="business_days[]" value="<?=$i+1?>" <?=in_array($i+1,$days,true)?'checked':''?>> <?=$d?></label><?php endforeach?></div><div class="field"><label>Business notification email</label><input type="email" name="admin_email" value="<?=e($settings['admin_email'])?>"><span class="help">Emails send when server mail is configured.</span></div><button class="primary-button" style="width:auto;padding:0 22px">Save availability</button></form></section></main><?php require __DIR__.'/includes/footer.php'; ?>
